INSERT INTO public.exam_version_listening_items (id, section_id, display_order, stem, options, correct_index) VALUES ('019db35e-ac14-73dc-80b7-33ddaf687457', '019db35e-ac12-72d8-ac57-ab8a8ccb91c3', 2, 'What evidence supports the sudden emergence theory?', '["Fossil records","Explosion of symbolic behavior 50,000 years ago","DNA analysis","Cave paintings from 200,000 years ago"]', 1);
INSERT INTO public.exam_version_listening_items (id, section_id, display_order, stem, options, correct_index) VALUES ('019db35e-ac15-721e-829f-4875f157194f', '019db35e-ac12-72d8-ac57-ab8a8ccb91c3', 3, 'What does the Sapir-Whorf hypothesis propose?', '["All languages are the same","Language shapes perception of reality","Language evolved from music","Animals can learn human language"]', 1);
INSERT INTO public.exam_version_listening_items (id, section_id, display_order, stem, options, correct_index) VALUES ('019db35e-ac16-7364-a74d-1bd720c806b9', '019db35e-ac12-72d8-ac57-ab8a8ccb91c3', 4, 'What does language enable according to the speaker?', '["Only communication","Culture, cooperation, and knowledge accumulation","Only writing","Only mathematics"]', 1);
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019da080-5449-7128-aa11-5fe693a4b2df', '019da080-5446-713a-8891-aa19bf52ad17', 1, 'Community Libraries', 15, 'Community libraries play an important role in modern society. They provide free access to books, computers, and the internet for people of all ages. Many libraries also offer educational programs such as reading clubs, language classes, and workshops for children and adults.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db357-983f-729d-837c-ea1ed90d25c7', '019da080-5446-713a-8891-aa19bf52ad17', 2, 'The Rise of Remote Work', 15, 'The COVID-19 pandemic accelerated a trend that had been growing for years: remote work. Millions of employees worldwide shifted to working from home almost overnight. Companies that had resisted flexible working arrangements were forced to adapt quickly.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db357-eac3-73a8-878e-ace46bcadc4a', '019da080-5446-713a-8891-aa19bf52ad17', 3, 'Plastic Pollution and Ocean Health', 15, 'Plastic pollution has become one of the most pressing environmental challenges of the 21st century. Every year, approximately 8 million tonnes of plastic waste enter the world oceans, threatening marine ecosystems and the species that depend on them.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db358-4e6a-7119-b2ce-e9011e7836f1', '019da080-5446-713a-8891-aa19bf52ad17', 4, 'The Psychology of Decision-Making', 15, 'Human decision-making is far more complex than classical economic theory suggests. For decades, economists assumed that people make rational choices based on complete information and self-interest. However, research in behavioral economics and cognitive psychology has revealed that human judgment is systematically biased in predictable ways.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db35a-fb43-71a7-a214-7a4d7ab52fb8', '019db356-9de1-7328-a7dc-56af4e4756e7', 1, 'Volunteering in Your Community', 15, 'Volunteering is the act of giving your time and skills to help others without receiving payment. Millions of people around the world volunteer in their communities, contributing to a wide range of causes including education, healthcare, environmental protection, and social welfare.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db35b-6154-71f0-a7b2-2bfc63404548', '019db356-9de1-7328-a7dc-56af4e4756e7', 2, 'The Sharing Economy', 15, 'The sharing economy refers to a system where individuals share access to goods and services, typically facilitated by digital platforms. Companies like Airbnb, Uber, and TaskRabbit have built billion-dollar businesses by connecting people who have underutilized assets with those who need them.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db35c-5104-72b5-a1b8-5e9d6e01a5f5', '019db356-9de1-7328-a7dc-56af4e4756e7', 3, 'Sleep Science and Modern Life', 15, 'Sleep is one of the most fundamental biological needs, yet it is increasingly neglected in modern society. Research indicates that approximately one-third of adults in developed countries regularly fail to get the recommended seven to nine hours of sleep per night. The consequences of this widespread sleep deprivation are far-reaching and serious.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db35c-c422-70a2-b549-09fb5f41b2a5', '019db356-9de1-7328-a7dc-56af4e4756e7', 4, 'Artificial Intelligence and the Future of Work', 15, 'Artificial intelligence is transforming the global economy at an unprecedented pace. Unlike previous waves of automation, which primarily displaced manual and routine cognitive tasks, modern AI systems are increasingly capable of performing complex analytical, creative, and interpersonal functions that were previously considered uniquely human.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db35f-5861-7146-a816-6978161e33d5', '019db356-9de3-72c7-a710-26c3b272542d', 1, 'The Benefits of Exercise', 15, 'Regular physical exercise is one of the most beneficial things a person can do for their health. Doctors and health organizations worldwide recommend at least 150 minutes of moderate exercise per week for adults. Despite this advice, many people lead sedentary lifestyles, spending most of their day sitting at desks or in front of screens.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db35f-b3d4-701a-a789-f461a4059d22', '019db356-9de3-72c7-a710-26c3b272542d', 2, 'Food Security in the 21st Century', 15, 'Food security exists when all people, at all times, have physical and economic access to sufficient, safe, and nutritious food to meet their dietary needs. Despite significant progress in reducing hunger over the past decades, food insecurity remains a major global challenge. According to the United Nations, approximately 800 million people worldwide are chronically undernourished.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', '019db356-9de3-72c7-a710-26c3b272542d', 3, 'The Neuroscience of Learning', 15, 'Recent advances in neuroscience have transformed our understanding of how the brain learns and how this knowledge can be applied to improve education. The brain is not a fixed organ but a dynamic system that changes in response to experience, a property known as neuroplasticity.
INSERT INTO public.exam_version_reading_passages (id, exam_version_id, part, title, duration_minutes, passage, display_order) VALUES ('019db360-6dec-70de-8145-459360b59b8d', '019db356-9de3-72c7-a710-26c3b272542d', 4, 'Globalization and Cultural Identity', 15, 'Globalization, the process by which the world is becoming increasingly interconnected through trade, communication, and cultural exchange, has profoundly transformed societies around the world. While it has brought undeniable economic benefits and facilitated the spread of ideas, it has also raised complex questions about cultural identity and the preservation of local traditions.
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019da080-5449-7128-aa11-5fe6945d61ec', '019da080-5449-7128-aa11-5fe693a4b2df', 0, 'What is the main idea of the passage?', '["Technology is harmful","Technology transforms education","Education is declining","Students dislike technology"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db357-0093-70be-b583-4f614ce70da6', '019da080-5449-7128-aa11-5fe693a4b2df', 1, 'Which of the following is NOT mentioned as a library service?', '["Reading clubs","Language classes","Cooking lessons","Workshops"]', 2);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db357-0095-72ea-a73b-7e4295445934', '019da080-5449-7128-aa11-5fe693a4b2df', 2, 'What unusual items do some libraries lend?', '["Cars and bicycles","Tools, instruments, and board games","Clothes and furniture","Sports equipment"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db357-0096-73ab-a1bb-fce7bd3b1133', '019da080-5449-7128-aa11-5fe693a4b2df', 3, 'According to the passage, why do people visit libraries?', '["Only to borrow books","To borrow books, use computers, and attend events","Only to use computers","Only to attend events"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db357-0097-72aa-aaf3-1bca1321eba5', '019da080-5449-7128-aa11-5fe693a4b2df', 4, 'How do libraries support senior citizens?', '["By offering free meals","By providing large-print books and audiobooks","By giving free computers","By organizing sports events"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db357-0098-7275-adf6-18f54b6ad4c4', '019da080-5449-7128-aa11-5fe693a4b2df', 5, 'What is described as a major challenge for libraries?', '["Lack of books","Funding","Too many visitors","Staff shortages"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db357-0098-7275-adf6-18f54c2cd500', '019da080-5449-7128-aa11-5fe693a4b2df', 6, 'What does the word supplement mean in paragraph 5?', '["Replace","Reduce","Add to","Remove"]', 2);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db357-0099-72a0-937b-b5e84ea27c61', '019da080-5449-7128-aa11-5fe693a4b2df', 7, 'What is the main idea of the passage?', '["Libraries are old-fashioned","Libraries are vital community resources","Libraries are too expensive","Libraries only help children"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db357-009a-72c6-a533-8ad3308fcaab', '019da080-5449-7128-aa11-5fe693a4b2df', 8, 'Which group benefits from career development resources?', '["Children","Senior citizens","Adults","All of the above"]', 2);
