INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35c-c42d-72bb-a681-ce04a53f46a4', '019db35c-c422-70a2-b549-09fb5f41b2a5', 5, 'What does the word accrue mean in paragraph 4?', '["Decrease","Accumulate or build up","Distribute equally","Disappear"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35c-c42e-70b6-bb38-0c3af069162f', '019db35c-c422-70a2-b549-09fb5f41b2a5', 6, 'What is universal basic income proposed to do?', '["Replace all jobs","Provide a safety net for displaced workers","Fund AI research","Tax technology companies"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35c-c42f-712d-8577-2c37148a6618', '019db35c-c422-70a2-b549-09fb5f41b2a5', 7, 'What skills does the author suggest emphasizing in education?', '["Technical coding skills","Critical thinking, creativity, and emotional intelligence","Data entry and accounting","Manufacturing skills"]', 1);
