INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-5866-72af-993a-0f06ac2cf6b0', '019db35f-5861-7146-a816-6978161e33d5', 0, 'How much exercise do health organizations recommend per week?', '["100 minutes","150 minutes","200 minutes","250 minutes"]', 1);
