INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-5869-7362-986c-8a22b652ea26', '019db35f-5861-7146-a816-6978161e33d5', 3, 'How effective is exercise for mild depression?', '["Less effective than medication","As effective as medication","More effective than medication","Not effective at all"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-586a-7151-b246-487b430d4072', '019db35f-5861-7146-a816-6978161e33d5', 4, 'What is listed as a barrier to exercise?', '["Too much energy","Lack of time and motivation","Too many gym options","Excessive health"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-586b-7217-a9b9-316451871314', '019db35f-5861-7146-a816-6978161e33d5', 5, 'What simple activity is suggested to increase exercise?', '["Buying expensive equipment","Taking the stairs instead of the lift","Joining a sports team","Running marathons"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-586c-73a2-a7a8-b62d9110216f', '019db35f-5861-7146-a816-6978161e33d5', 6, 'What does the word sedentary mean in paragraph 1?', '["Very active","Involving little physical activity","Healthy","Outdoors"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-586c-73a2-a7a8-b62d914c935b', '019db35f-5861-7146-a816-6978161e33d5', 7, 'What approach does the author recommend for beginners?', '["Intense daily workouts","Starting slowly and gradually increasing","Exercising only on weekends","Joining a gym immediately"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-586f-7023-95d9-f3bc0fcb9994', '019db35f-5861-7146-a816-6978161e33d5', 8, 'What is described as the key to exercise success?', '["Intensity","Consistency","Expensive equipment","Professional coaching"]', 0);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-5870-73aa-b2e6-5bd12972757a', '019db35f-5861-7146-a816-6978161e33d5', 9, 'What is the main message of the passage?', '["Exercise is only for young people","Regular exercise has significant physical and mental benefits","Exercise requires expensive equipment","Only intense exercise is beneficial"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-b3da-7255-8252-d70c9747b94a', '019db35f-b3d4-701a-a789-f461a4059d22', 0, 'How many people are chronically undernourished?', '["400 million","600 million","800 million","1 billion"]', 2);
