INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-b3dc-7276-b262-557856ce8c26', '019db35f-b3d4-701a-a789-f461a4059d22', 3, 'What does precision agriculture do?', '["Replace all farmers","Optimize crop yields while minimizing resource use","Only grow organic food","Eliminate pesticides"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-b3dd-73ce-bf26-423ec9c97b6b', '019db35f-b3d4-701a-a789-f461a4059d22', 4, 'Where does most food waste occur in developed countries?', '["During production","During storage","At the consumer level","During transport"]', 2);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-b3dd-73ce-bf26-423eca08e5e2', '019db35f-b3d4-701a-a789-f461a4059d22', 5, 'What proportion of food produced globally is wasted?', '["One quarter","One third","One half","One fifth"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-b3de-7097-b003-7daaea68e5da', '019db35f-b3d4-701a-a789-f461a4059d22', 6, 'What does the word staple mean in paragraph 2?', '["Luxury","Basic and widely consumed","Expensive","Imported"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-b3de-7097-b003-7daaeb63bb32', '019db35f-b3d4-701a-a789-f461a4059d22', 7, 'Who does the author say is particularly important to support?', '["Large corporations","Smallholder farmers","Urban consumers","Food scientists"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-b3df-7036-b5be-0edd5ecf516f', '019db35f-b3d4-701a-a789-f461a4059d22', 8, 'What is the main challenge described in the passage?', '["Too much food production","Feeding a growing population sustainably despite climate change","Lack of technology","High food prices"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db35f-b3df-7036-b5be-0edd5f479fb2', '019db35f-b3d4-701a-a789-f461a4059d22', 9, 'What is the tone of the passage?', '["Alarmist","Optimistic","Analytical and solution-focused","Pessimistic"]', 2);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-0c50-727b-9909-ed379bd2dcb4', '019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', 0, 'What is neuroplasticity?', '["The brain becoming smaller with age","The brain changing in response to experience","The brain being fixed and unchangeable","The brain growing larger"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-0c51-7371-84b4-02dbd241b2ff', '019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', 1, 'What is synaptic plasticity?', '["The brain becoming more flexible","The cellular basis of memory and learning","A type of brain damage","A learning disorder"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-0c51-7371-84b4-02dbd2e6f8dd', '019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', 2, 'What does spaced repetition involve?', '["Studying in one long session","Spacing practice over time","Only studying before exams","Avoiding repetition"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-0c52-734e-8fbf-3386168d22bf', '019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', 3, 'What is the testing effect?', '["Tests cause anxiety","Testing yourself strengthens memory better than re-reading","Tests are ineffective","Only written tests help learning"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-0c53-739f-ae65-fc0b8aeb112b', '019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', 4, 'What happens to memories during sleep?', '["They are forgotten","They are replayed and consolidated","They become stronger without sleep","They are transferred to long-term memory immediately"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-0c54-7326-a66a-4ac7666d8e0b', '019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', 5, 'What level of stress enhances learning?', '["No stress","Moderate stress","High stress","Chronic stress"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-0c55-7394-bcf7-a2ab1b943623', '019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', 6, 'What does the word retrieval mean in paragraph 4?', '["Storing information","Forgetting information","Recalling information from memory","Reading information"]', 2);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-0c56-736c-b506-eccb5374349c', '019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', 7, 'What promotes deep learning according to the passage?', '["High stress","Positive emotions and a sense of safety","Competitive environments","Frequent testing only"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-0c56-736c-b506-eccb53d61834', '019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', 8, 'What is the main topic of the passage?', '["How to pass exams","Neuroscience insights that can improve learning","Why students fail","The history of education"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-0c58-728a-939d-1ff32ae23416', '019db360-0c4c-70bd-8aeb-0b2bd34a1d3c', 9, 'What implication does the passage have for classrooms?', '["Students should study alone","Classroom environments should promote positive emotions","Tests should be eliminated","Sleep is not important for students"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-6df0-727f-93b1-bd8e599485a4', '019db360-6dec-70de-8145-459360b59b8d', 0, 'What is cultural homogenization?', '["Cultures becoming more diverse","Diverse cultures becoming increasingly similar","The spread of local cultures","Cultural preservation"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-6df2-71a8-bc50-53c000587d41', '019db360-6dec-70de-8145-459360b59b8d', 1, 'What is often cited as evidence of American cultural dominance?', '["American universities","Hollywood films, fast food, and social media","American sports","American literature"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-6df3-713d-9e7b-c5fd6e24a42d', '019db360-6dec-70de-8145-459360b59b8d', 2, 'What is cultural hybridization?', '["The destruction of local culture","The creative blending of global and local elements","The rejection of all foreign influences","Cultural isolation"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-6df4-7072-8915-6bc0f3325ff8', '019db360-6dec-70de-8145-459360b59b8d', 3, 'What example of cultural hybridization is given?', '["American fast food","Vietnamese hip-hop","British television","Chinese manufacturing"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-6df5-7213-bf06-c19222b530ac', '019db360-6dec-70de-8145-459360b59b8d', 4, 'How do indigenous communities use social media?', '["To spread American culture","To document and share their cultural practices","To oppose globalization","To learn foreign languages"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-6df5-7213-bf06-c192237a1077', '019db360-6dec-70de-8145-459360b59b8d', 5, 'What shapes how communities experience globalization?', '["Geography","Economic inequality","Language","Religion"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-6df6-7226-a512-f1486d0722cd', '019db360-6dec-70de-8145-459360b59b8d', 6, 'What does the word permeates mean in paragraph 2?', '["Destroys","Spreads throughout","Avoids","Replaces"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-6df7-70e6-89f0-4f5285db329c', '019db360-6dec-70de-8145-459360b59b8d', 7, 'What does the author suggest societies should do?', '["Reject globalization entirely","Embrace globalization completely","Participate in global culture while maintaining diversity","Isolate themselves from global influences"]', 2);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-6df7-70e6-89f0-4f5286a2b463', '019db360-6dec-70de-8145-459360b59b8d', 8, 'What policy does the author recommend?', '["Banning foreign media","Supporting minority languages and cultural education","Restricting trade","Promoting only global culture"]', 1);
INSERT INTO public.exam_version_reading_items (id, passage_id, display_order, stem, options, correct_index) VALUES ('019db360-6df8-7168-9171-239c16c0a47e', '019db360-6dec-70de-8145-459360b59b8d', 9, 'What is the main argument of the passage?', '["Globalization is entirely negative","Globalization destroys all local cultures","Globalization has complex effects on cultural identity requiring thoughtful responses","Globalization is inevitable and unstoppable"]', 2);
INSERT INTO public.exam_version_speaking_parts (id, exam_version_id, part, type, duration_minutes, speaking_seconds, content, display_order) VALUES ('019da080-544d-716a-8566-4ac5f4fa1ae8', '019da080-5446-713a-8891-aa19bf52ad17', 1, 'social', 3, 180, '{"topics":[{"name":"Daily Routine","questions":["Tell me about your typical day.","What do you usually do in the evenings?","How do you spend your weekends?"]},{"name":"Hobbies","questions":["What are your hobbies?","How long have you had this hobby?","Why do you enjoy it?"]}]}', 0);
INSERT INTO public.exam_version_speaking_parts (id, exam_version_id, part, type, duration_minutes, speaking_seconds, content, display_order) VALUES ('019db358-98e2-70d6-9175-7fd144f5b7f6', '019da080-5446-713a-8891-aa19bf52ad17', 2, 'solution', 4, 240, '{"situation":"Your city is experiencing serious traffic congestion. The local government is considering three solutions.","solutions":["Build more roads and highways","Improve public transport (buses and metro)","Introduce congestion charges for driving in the city center"],"task":"Choose ONE solution and explain why it is the best option. Consider the advantages and disadvantages of your chosen solution."}', 1);
INSERT INTO public.exam_version_speaking_parts (id, exam_version_id, part, type, duration_minutes, speaking_seconds, content, display_order) VALUES ('019db358-98e4-704b-888c-f805db7e939b', '019da080-5446-713a-8891-aa19bf52ad17', 3, 'topic', 5, 300, '{"topic":"The Impact of Social Media on Society","prompt":"Discuss the positive and negative effects of social media on modern society. Consider its impact on communication, relationships, mental health, and information sharing.","follow_up_questions":["Do you think social media does more harm than good?","How has social media changed the way people communicate?","What can individuals do to use social media more responsibly?"]}', 2);
INSERT INTO public.exam_version_speaking_parts (id, exam_version_id, part, type, duration_minutes, speaking_seconds, content, display_order) VALUES ('019db35a-fb57-70bf-9e49-33298a301561', '019db356-9de1-7328-a7dc-56af4e4756e7', 1, 'social', 3, 180, '{"topics":[{"name":"Food and Eating","questions":["What is your favorite food?","Do you prefer eating at home or in restaurants?","How often do you cook?"]},{"name":"Travel","questions":["Have you traveled abroad?","Where would you like to visit?","What do you enjoy about traveling?"]}]}', 0);
INSERT INTO public.exam_version_speaking_parts (id, exam_version_id, part, type, duration_minutes, speaking_seconds, content, display_order) VALUES ('019db35a-fb58-71cf-bebe-2fb4da6bf154', '019db356-9de1-7328-a7dc-56af4e4756e7', 2, 'solution', 4, 240, '{"situation":"Your school wants to improve students health and fitness. Three options are being considered.","solutions":["Add more physical education classes each week","Build a new sports facility on campus","Introduce a healthy eating program in the school canteen"],"task":"Choose ONE solution and explain why it is the best option."}', 1);
INSERT INTO public.exam_version_speaking_parts (id, exam_version_id, part, type, duration_minutes, speaking_seconds, content, display_order) VALUES ('019db35a-fb59-7015-b26b-b396c9e9e171', '019db356-9de1-7328-a7dc-56af4e4756e7', 3, 'topic', 5, 300, '{"topic":"Education and Technology","prompt":"Discuss how technology has changed education. Consider both the benefits and drawbacks of using technology in schools and universities.","follow_up_questions":["Do you think technology improves learning outcomes?","What are the risks of students relying too much on technology?","How should teachers adapt to technological changes?"]}', 2);
INSERT INTO public.exam_version_speaking_parts (id, exam_version_id, part, type, duration_minutes, speaking_seconds, content, display_order) VALUES ('019db35f-5873-7168-aced-223964a4c3dd', '019db356-9de3-72c7-a710-26c3b272542d', 1, 'social', 3, 180, '{"topics":[{"name":"Family","questions":["Tell me about your family.","How often do you spend time with your family?","What activities do you enjoy doing together?"]},{"name":"Work or Study","questions":["What do you do for work or study?","What do you enjoy most about it?","What are your future plans?"]}]}', 0);
INSERT INTO public.exam_version_speaking_parts (id, exam_version_id, part, type, duration_minutes, speaking_seconds, content, display_order) VALUES ('019db35f-5874-73b0-a67f-e8658d88baa7', '019db356-9de3-72c7-a710-26c3b272542d', 2, 'solution', 4, 240, '{"situation":"Your company wants to improve employee well-being and reduce stress. Three options are being considered.","solutions":["Offer flexible working hours","Provide free gym membership and wellness programs","Introduce a four-day working week"],"task":"Choose ONE solution and explain why it is the best option for improving employee well-being."}', 1);
INSERT INTO public.exam_version_speaking_parts (id, exam_version_id, part, type, duration_minutes, speaking_seconds, content, display_order) VALUES ('019db35f-5875-71db-ac20-450399aaca0d', '019db356-9de3-72c7-a710-26c3b272542d', 3, 'topic', 5, 300, '{"topic":"Environmental Responsibility","prompt":"Discuss the role of individuals, businesses, and governments in protecting the environment. Who has the greatest responsibility, and what actions should each take?","follow_up_questions":["Do you think individuals can make a real difference to environmental problems?","Should businesses be legally required to reduce their environmental impact?","What environmental policies have been most effective in your country?"]}', 2);
INSERT INTO public.exam_version_writing_tasks (id, exam_version_id, part, task_type, duration_minutes, prompt, min_words, instructions, display_order) VALUES ('019da080-544c-7353-8f90-b6f11f369842', '019da080-5446-713a-8891-aa19bf52ad17', 1, 'letter', 20, 'You recently attended a training course organized by your company. Write a letter to your manager to:
INSERT INTO public.exam_version_writing_tasks (id, exam_version_id, part, task_type, duration_minutes, prompt, min_words, instructions, display_order) VALUES ('019da080-544c-7353-8f90-b6f11f4c44a4', '019da080-5446-713a-8891-aa19bf52ad17', 2, 'essay', 40, 'Some people believe that technology has made our lives easier and more convenient. Others argue that it has created new problems and made life more stressful. Discuss both views and give your own opinion.', 250, '["Discuss both views","Give your own opinion","Use examples to support your arguments"]', 1);
INSERT INTO public.exam_version_writing_tasks (id, exam_version_id, part, task_type, duration_minutes, prompt, min_words, instructions, display_order) VALUES ('019db35a-fb55-7050-996c-35d90769d36f', '019db356-9de1-7328-a7dc-56af4e4756e7', 1, 'letter', 20, 'You borrowed a book from a friend and accidentally damaged it. Write a letter to your friend to:
INSERT INTO public.exam_version_writing_tasks (id, exam_version_id, part, task_type, duration_minutes, prompt, min_words, instructions, display_order) VALUES ('019db35a-fb56-71f0-bdbf-4fb62efaa984', '019db356-9de1-7328-a7dc-56af4e4756e7', 2, 'essay', 40, 'Many young people today prefer to live in cities rather than in rural areas. What are the advantages and disadvantages of city life for young people? Give your opinion.', 250, '["Discuss advantages","Discuss disadvantages","Give your opinion"]', 1);
INSERT INTO public.exam_version_writing_tasks (id, exam_version_id, part, task_type, duration_minutes, prompt, min_words, instructions, display_order) VALUES ('019db35f-5871-7182-8724-6f9c7bc9d303', '019db356-9de3-72c7-a710-26c3b272542d', 1, 'letter', 20, 'You have seen an advertisement for a part-time job that interests you. Write a letter to the employer to:
INSERT INTO public.exam_version_writing_tasks (id, exam_version_id, part, task_type, duration_minutes, prompt, min_words, instructions, display_order) VALUES ('019db35f-5872-7170-8022-925405532637', '019db356-9de3-72c7-a710-26c3b272542d', 2, 'essay', 40, 'In many countries, people are living longer than ever before. What are the advantages and disadvantages of an aging population? What measures can governments take to address the challenges?', 250, '["Discuss advantages","Discuss disadvantages","Suggest government measures"]', 1);
INSERT INTO public.grammar_points (id, slug, name, vietnamese_name, summary, category, display_order, is_published, created_at, updated_at) VALUES ('019da080-5431-70ff-879a-291264d520f9', 'present-perfect', 'Present Perfect', 'Thì hiện tại hoàn thành', 'Diễn tả hành động đã xảy ra và có liên hệ với hiện tại, hoặc trong khoảng thời gian chưa kết thúc.', 'foundation', 1, true, '2026-04-18 12:10:57', '2026-04-22 03:53:49');
INSERT INTO public.grammar_points (id, slug, name, vietnamese_name, summary, category, display_order, is_published, created_at, updated_at) VALUES ('019db352-e5e8-71cb-b823-fb7267deae77', 'passive-voice', 'Passive Voice', 'Câu bị động', 'Dùng khi muốn nhấn mạnh đối tượng chịu tác động thay vì chủ thể thực hiện hành động.', 'foundation', 2, true, '2026-04-22 03:54:07', '2026-04-22 03:54:07');
INSERT INTO public.grammar_points (id, slug, name, vietnamese_name, summary, category, display_order, is_published, created_at, updated_at) VALUES ('019db353-4972-712f-a59a-65ee965fdbad', 'conditional-sentences', 'Conditional Sentences', 'Câu điều kiện', 'Diễn tả điều kiện và kết quả. Type 1 (có thể xảy ra), Type 2 (giả định), Type 3 (không thể xảy ra).', 'foundation', 3, true, '2026-04-22 03:54:33', '2026-04-22 03:54:33');
INSERT INTO public.grammar_points (id, slug, name, vietnamese_name, summary, category, display_order, is_published, created_at, updated_at) VALUES ('019db353-9503-70c9-aa6b-e66b5d472234', 'relative-clauses', 'Relative Clauses', 'Mệnh đề quan hệ', 'Dùng để bổ nghĩa cho danh từ. Hai loại: defining (xác định) và non-defining (không xác định).', 'foundation', 4, true, '2026-04-22 03:54:52', '2026-04-22 03:54:52');
INSERT INTO public.grammar_points (id, slug, name, vietnamese_name, summary, category, display_order, is_published, created_at, updated_at) VALUES ('019db353-ded2-7348-8607-6426d410f8c3', 'modal-verbs', 'Modal Verbs', 'Động từ khuyết thiếu', 'Diễn tả khả năng, sự cho phép, nghĩa vụ, lời khuyên. Gồm: can, could, may, might, must, should, would.', 'foundation', 5, true, '2026-04-22 03:55:11', '2026-04-22 03:55:11');
INSERT INTO public.grammar_points (id, slug, name, vietnamese_name, summary, category, display_order, is_published, created_at, updated_at) VALUES ('019db354-6281-712e-b01a-c37789241547', 'reported-speech', 'Reported Speech', 'Câu tường thuật', 'Dùng để thuật lại lời nói của người khác. Thì động từ lùi về quá khứ.', 'foundation', 6, true, '2026-04-22 03:55:45', '2026-04-22 03:55:45');
INSERT INTO public.grammar_points (id, slug, name, vietnamese_name, summary, category, display_order, is_published, created_at, updated_at) VALUES ('019db354-cb0a-70e6-997d-3c9ee87bfcdd', 'articles', 'Articles (a/an/the)', 'Mạo từ', 'a/an dùng cho danh từ đếm được số ít lần đầu nhắc đến. the dùng khi đã xác định hoặc duy nhất.', 'foundation', 7, true, '2026-04-22 03:56:11', '2026-04-22 03:56:11');
INSERT INTO public.grammar_points (id, slug, name, vietnamese_name, summary, category, display_order, is_published, created_at, updated_at) VALUES ('019db355-1c7b-70e1-b753-ec6176efcd01', 'gerunds-infinitives', 'Gerunds & Infinitives', 'Danh động từ và động từ nguyên mẫu', 'Gerund (V-ing) và infinitive (to + V) dùng sau một số động từ nhất định. Một số động từ dùng được cả hai nhưng nghĩa khác nhau.', 'foundation', 8, true, '2026-04-22 03:56:32', '2026-04-22 03:56:32');
INSERT INTO public.grammar_points (id, slug, name, vietnamese_name, summary, category, display_order, is_published, created_at, updated_at) VALUES ('019db355-6f5a-70d9-97e4-9862ed349b16', 'comparison', 'Comparison', 'So sánh', 'So sánh hơn (comparative), so sánh nhất (superlative), so sánh bằng (as...as). Dùng nhiều trong writing và speaking.', 'foundation', 9, true, '2026-04-22 03:56:53', '2026-04-22 03:56:53');
INSERT INTO public.grammar_points (id, slug, name, vietnamese_name, summary, category, display_order, is_published, created_at, updated_at) VALUES ('019db355-e3a3-71d2-94a3-37f86d562d3c', 'conjunctions-linking', 'Conjunctions & Linking Words', 'Liên từ và từ nối', 'Dùng để kết nối ý trong câu và đoạn văn. Quan trọng cho writing: addition, contrast, cause/effect, concession.', 'writing', 10, true, '2026-04-22 03:57:23', '2026-04-22 03:57:23');
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019da080-5437-7380-9760-816d73c69d92', '019da080-5431-70ff-879a-291264d520f9', 'I have live here.', 'I have lived here.', 'Phải dùng V3/ed sau have/has.', 0);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db352-9dfe-71c8-b068-1087b753a64c', '019da080-5431-70ff-879a-291264d520f9', 'She has went to school.', 'She has gone to school.', 'Go → gone (bất quy tắc).', 1);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db352-e5f8-73bd-b984-c4cf71a271d7', '019db352-e5e8-71cb-b823-fb7267deae77', 'The letter was wrote by her.', 'The letter was written by her.', 'Write → written (bất quy tắc).', 0);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db353-4980-73c6-b8d5-7a6221ed121e', '019db353-4972-712f-a59a-65ee965fdbad', 'If I will go, I will call you.', 'If I go, I will call you.', 'Mệnh đề if không dùng will.', 0);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db353-4981-71f7-a1bc-dc2d8400a7d5', '019db353-4972-712f-a59a-65ee965fdbad', 'If he studied, he will pass.', 'If he studied, he would pass.', 'Type 2: if + past → would + V.', 1);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db353-9513-7006-9799-52c8a6687639', '019db353-9503-70c9-aa6b-e66b5d472234', 'The man which called you is here.', 'The man who called you is here.', 'Dùng who cho người, which cho vật.', 0);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db353-9513-7006-9799-52c8a72f3cce', '019db353-9503-70c9-aa6b-e66b5d472234', 'She is the girl whose her bag was stolen.', 'She is the girl whose bag was stolen.', 'Sau whose không dùng thêm her/his.', 1);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db353-dee0-73d6-8bdb-f61781f4c40c', '019db353-ded2-7348-8607-6426d410f8c3', 'You must to go now.', 'You must go now.', 'Modal verbs không dùng to trước động từ.', 0);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db353-dee1-7100-baa3-c6baa3b6c62f', '019db353-ded2-7348-8607-6426d410f8c3', 'She can sings well.', 'She can sing well.', 'Sau modal dùng bare infinitive, không chia.', 1);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db354-628d-7118-a783-121a14620b1a', '019db354-6281-712e-b01a-c37789241547', 'She said she is tired.', 'She said she was tired.', 'Lùi thì: is → was.', 0);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db354-628e-7361-8dcb-e4629886dab0', '019db354-6281-712e-b01a-c37789241547', 'He asked where do I live.', 'He asked where I lived.', 'Câu hỏi gián tiếp dùng trật tự câu khẳng định.', 1);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db354-cb17-7120-8bd8-692bedf80c6c', '019db354-cb0a-70e6-997d-3c9ee87bfcdd', 'She is a honest person.', 'She is an honest person.', 'Dùng an trước âm nguyên âm (h câm).', 0);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db354-cb18-708b-8c3c-dea74095cf19', '019db354-cb0a-70e6-997d-3c9ee87bfcdd', 'I go to the school every day.', 'I go to school every day.', 'Không dùng the với school/work/church khi nói về mục đích.', 1);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db355-1c8a-7287-8d7b-0b9aa3e226d6', '019db355-1c7b-70e1-b753-ec6176efcd01', 'She enjoys to read.', 'She enjoys reading.', 'enjoy + V-ing, không dùng to + V.', 0);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db355-1c8b-7355-b2c2-5c882869fd2e', '019db355-1c7b-70e1-b753-ec6176efcd01', 'He wants studying abroad.', 'He wants to study abroad.', 'want + to + V.', 1);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db355-6f69-7157-b41f-09f11f8eeaa6', '019db355-6f5a-70d9-97e4-9862ed349b16', 'She is more taller than her sister.', 'She is taller than her sister.', 'Không dùng more với tính từ ngắn.', 0);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db355-6f6a-7030-afe8-6fc868eba6dc', '019db355-6f5a-70d9-97e4-9862ed349b16', 'He is the most tallest student.', 'He is the tallest student.', 'Không dùng most với tính từ ngắn.', 1);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db355-e3b3-73dd-8aa7-7174615977f2', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'Although it was cold, but she went out.', 'Although it was cold, she went out.', 'Không dùng although và but cùng lúc.', 0);
INSERT INTO public.grammar_common_mistakes (id, grammar_point_id, wrong, correct, explanation, display_order) VALUES ('019db355-e3b4-70be-bee8-e5aaa6a49b17', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'Despite of the rain, we went out.', 'Despite the rain, we went out.', 'Despite không dùng of, dùng in spite of nếu muốn.', 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019da080-5436-700b-a615-3207e08e290a', '019da080-5431-70ff-879a-291264d520f9', 'I have lived here for five years.', 'Tôi đã sống ở đây 5 năm.', NULL, 0);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db352-9dfc-7033-90bd-4e57d5c0f423', '019da080-5431-70ff-879a-291264d520f9', 'She has never visited Paris.', 'Cô ấy chưa bao giờ đến Paris.', NULL, 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db352-e5f6-7030-be03-2fbedeed9ee7', '019db352-e5e8-71cb-b823-fb7267deae77', 'The report was written by the manager.', 'Báo cáo được viết bởi người quản lý.', NULL, 0);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db352-e5f7-73fe-8c87-d0cbbc297fd0', '019db352-e5e8-71cb-b823-fb7267deae77', 'New policies will be introduced next year.', 'Các chính sách mới sẽ được giới thiệu năm tới.', NULL, 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db353-497d-72f1-b719-4b8891e4f805', '019db353-4972-712f-a59a-65ee965fdbad', 'If it rains, we will cancel the trip.', 'Nếu trời mưa, chúng tôi sẽ hủy chuyến đi.', NULL, 0);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db353-497d-72f1-b719-4b889294c140', '019db353-4972-712f-a59a-65ee965fdbad', 'If I had more time, I would study harder.', 'Nếu tôi có nhiều thời gian hơn, tôi sẽ học chăm hơn.', NULL, 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db353-497e-706a-b49e-97e45ac9ae47', '019db353-4972-712f-a59a-65ee965fdbad', 'If she had studied, she would have passed.', 'Nếu cô ấy đã học, cô ấy đã đỗ rồi.', NULL, 2);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db353-9510-7122-aab1-f9c0c67f4fd5', '019db353-9503-70c9-aa6b-e66b5d472234', 'The student who studies hard will succeed.', 'Học sinh nào học chăm sẽ thành công.', NULL, 0);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db353-9511-73e2-beda-683713d2dcd7', '019db353-9503-70c9-aa6b-e66b5d472234', 'My sister, who lives in Hanoi, is a doctor.', 'Chị gái tôi, người sống ở Hà Nội, là bác sĩ.', 'Non-defining: có dấu phẩy', 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db353-dedd-72e0-8e51-62e16787fbd9', '019db353-ded2-7348-8607-6426d410f8c3', 'You should exercise regularly.', 'Bạn nên tập thể dục thường xuyên.', NULL, 0);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db353-dede-7088-8916-5019c6f2de3c', '019db353-ded2-7348-8607-6426d410f8c3', 'She must have forgotten the meeting.', 'Cô ấy chắc đã quên cuộc họp rồi.', NULL, 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db353-dede-7088-8916-5019c6f8b55d', '019db353-ded2-7348-8607-6426d410f8c3', 'It might rain this afternoon.', 'Chiều nay có thể trời mưa.', NULL, 2);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db354-628a-7123-9299-211b95bf65f4', '019db354-6281-712e-b01a-c37789241547', 'She said she was tired.', 'Cô ấy nói rằng cô ấy mệt.', NULL, 0);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db354-628b-7387-93cf-0e730b594860', '019db354-6281-712e-b01a-c37789241547', 'He asked if I had finished.', 'Anh ấy hỏi tôi đã xong chưa.', NULL, 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db354-cb14-7115-9065-ea1a33201872', '019db354-cb0a-70e6-997d-3c9ee87bfcdd', 'I saw a dog. The dog was barking.', 'Tôi thấy một con chó. Con chó đó đang sủa.', 'a = lần đầu, the = đã biết', 0);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db354-cb15-72b9-aa26-5fb3e7f1e2af', '019db354-cb0a-70e6-997d-3c9ee87bfcdd', 'The sun rises in the east.', 'Mặt trời mọc ở phía đông.', 'the = duy nhất', 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db355-1c87-717b-8f08-7b27e2c4068f', '019db355-1c7b-70e1-b753-ec6176efcd01', 'She enjoys reading novels.', 'Cô ấy thích đọc tiểu thuyết.', NULL, 0);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db355-1c87-717b-8f08-7b27e33db574', '019db355-1c7b-70e1-b753-ec6176efcd01', 'He decided to study abroad.', 'Anh ấy quyết định du học.', NULL, 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db355-1c88-7108-ae73-e9566db58d6d', '019db355-1c7b-70e1-b753-ec6176efcd01', 'I stopped smoking. vs I stopped to smoke.', 'Tôi bỏ hút thuốc. vs Tôi dừng lại để hút thuốc.', 'Nghĩa khác nhau', 2);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db355-6f66-707a-892c-cda298f895ee', '019db355-6f5a-70d9-97e4-9862ed349b16', 'Cities are more expensive than rural areas.', 'Thành phố đắt đỏ hơn vùng nông thôn.', NULL, 0);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db355-6f68-71bc-8247-b57b832c5651', '019db355-6f5a-70d9-97e4-9862ed349b16', 'This is the most important issue of our time.', 'Đây là vấn đề quan trọng nhất của thời đại chúng ta.', NULL, 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db355-e3af-71f5-9978-41aafb052917', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'Technology improves efficiency. Furthermore, it reduces costs.', 'Công nghệ cải thiện hiệu quả. Hơn nữa, nó giảm chi phí.', NULL, 0);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db355-e3b0-71a3-87d9-04938cac1be5', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'Although it was raining, they continued the match.', 'Mặc dù trời mưa, họ vẫn tiếp tục trận đấu.', NULL, 1);
INSERT INTO public.grammar_examples (id, grammar_point_id, en, vi, note, display_order) VALUES ('019db355-e3b1-72c3-a2dd-a73e63e04dfd', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'The factory pollutes the river. As a result, fish are dying.', 'Nhà máy gây ô nhiễm sông. Kết quả là cá đang chết.', NULL, 2);
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019da080-543a-70f8-a751-a76a77a354eb', '019da080-5431-70ff-879a-291264d520f9', 'mcq', '{"prompt":"She ___ (live) here since 2020.","options":["lived","has lived","is living","was living"],"correct_index":1}', 'Since + mốc thời gian → present perfect.', 0, '2026-04-18 12:10:57', '2026-04-18 12:10:57');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019da080-543b-7101-bdc8-69f544937a38', '019da080-5431-70ff-879a-291264d520f9', 'fill_blank', '{"template":"They ___ (not finish) the project yet.","accepted_answers":["haven''t finished","have not finished"]}', 'Yet dùng với present perfect phủ định.', 1, '2026-04-18 12:10:57', '2026-04-18 12:10:57');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db352-e5fc-737b-b628-d39f61a06fad', '019db352-e5e8-71cb-b823-fb7267deae77', 'mcq', '{"prompt":"The new bridge ___ last year.","options":["built","was built","has built","is building"],"correct_index":1}', 'Hành động hoàn thành trong quá khứ → was built.', 0, '2026-04-22 03:54:07', '2026-04-22 03:54:07');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db352-e5fe-722c-9a62-1e1ffc442f2d', '019db352-e5e8-71cb-b823-fb7267deae77', 'fill_blank', '{"template":"English ___ (speak) in many countries.","accepted_answers":["is spoken","is widely spoken"]}', 'Bị động thì hiện tại đơn.', 1, '2026-04-22 03:54:07', '2026-04-22 03:54:07');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db353-4983-732e-ae95-4a3b49e28079', '019db353-4972-712f-a59a-65ee965fdbad', 'mcq', '{"prompt":"If she ___ harder, she would get better grades.","options":["studies","studied","will study","had studied"],"correct_index":1}', 'Type 2: if + past simple → would + V.', 0, '2026-04-22 03:54:33', '2026-04-22 03:54:33');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db353-4984-7188-8834-902b7eb3cec3', '019db353-4972-712f-a59a-65ee965fdbad', 'mcq', '{"prompt":"If they had left earlier, they ___ the train.","options":["catch","would catch","would have caught","had caught"],"correct_index":2}', 'Type 3: would have + V3.', 1, '2026-04-22 03:54:33', '2026-04-22 03:54:33');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db353-9517-7288-af35-4646ba2054da', '019db353-9503-70c9-aa6b-e66b5d472234', 'mcq', '{"prompt":"The teacher ___ taught me English retired last year.","options":["which","whose","who","whom"],"correct_index":2}', 'Who dùng cho người làm chủ ngữ.', 0, '2026-04-22 03:54:52', '2026-04-22 03:54:52');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db353-9517-7288-af35-4646ba4e1e44', '019db353-9503-70c9-aa6b-e66b5d472234', 'mcq', '{"prompt":"She has a friend ___ father is a famous writer.","options":["who","which","whose","whom"],"correct_index":2}', 'Whose dùng để chỉ sở hữu.', 1, '2026-04-22 03:54:52', '2026-04-22 03:54:52');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db353-dee4-73c1-823d-48decb3cf9f2', '019db353-ded2-7348-8607-6426d410f8c3', 'mcq', '{"prompt":"You ___ smoke in the hospital. It is forbidden.","options":["should","must not","might not","could not"],"correct_index":1}', 'Must not = cấm tuyệt đối.', 0, '2026-04-22 03:55:11', '2026-04-22 03:55:11');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db353-dee5-7389-8c46-b3078ccbda4d', '019db353-ded2-7348-8607-6426d410f8c3', 'mcq', '{"prompt":"I ___ speak French when I was young, but I have forgotten it.","options":["can","could","may","should"],"correct_index":1}', 'Could = khả năng trong quá khứ.', 1, '2026-04-22 03:55:11', '2026-04-22 03:55:11');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db354-6291-7001-922e-efc2463d9caf', '019db354-6281-712e-b01a-c37789241547', 'mcq', '{"prompt":"I am studying, she said. She said she ___ studying.","options":["is","was","has been","will be"],"correct_index":1}', 'Is → was khi lùi thì.', 0, '2026-04-22 03:55:45', '2026-04-22 03:55:45');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db354-6292-7347-89b8-506cd44c2d7b', '019db354-6281-712e-b01a-c37789241547', 'mcq', '{"prompt":"The teacher told us ___ late.","options":["do not be","not to be","to not be","not being"],"correct_index":1}', 'Mệnh lệnh phủ định: told + not to + V.', 1, '2026-04-22 03:55:45', '2026-04-22 03:55:45');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db354-cb1a-700a-8ffa-cd351bf07c70', '019db354-cb0a-70e6-997d-3c9ee87bfcdd', 'mcq', '{"prompt":"She is ___ engineer at a tech company.","options":["a","an","the","no article"],"correct_index":1}', 'an trước âm nguyên âm /e/.', 0, '2026-04-22 03:56:11', '2026-04-22 03:56:11');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db354-cb1b-73f9-874a-4846f301fed9', '019db354-cb0a-70e6-997d-3c9ee87bfcdd', 'fill_blank', '{"template":"I bought ___ book yesterday. ___ book was very interesting.","accepted_answers":["a, The","a, the"]}', 'a = lần đầu, the = đã biết.', 1, '2026-04-22 03:56:11', '2026-04-22 03:56:11');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db355-1c8d-700e-8f12-4ad564f0c063', '019db355-1c7b-70e1-b753-ec6176efcd01', 'mcq', '{"prompt":"She suggested ___ to the cinema.","options":["go","to go","going","gone"],"correct_index":2}', 'suggest + V-ing.', 0, '2026-04-22 03:56:32', '2026-04-22 03:56:32');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db355-1c8f-705e-914e-10c0b0138875', '019db355-1c7b-70e1-b753-ec6176efcd01', 'mcq', '{"prompt":"They decided ___ a new house.","options":["buying","buy","to buy","bought"],"correct_index":2}', 'decide + to + V.', 1, '2026-04-22 03:56:32', '2026-04-22 03:56:32');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db355-6f6c-70e6-9533-54d599c1809c', '019db355-6f5a-70d9-97e4-9862ed349b16', 'mcq', '{"prompt":"This exam is ___ than the previous one.","options":["more difficult","most difficult","difficulter","the most difficult"],"correct_index":0}', 'more + tính từ dài để so sánh hơn.', 0, '2026-04-22 03:56:53', '2026-04-22 03:56:53');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db355-6f6d-721e-9399-839a42e45c85', '019db355-6f5a-70d9-97e4-9862ed349b16', 'fill_blank', '{"template":"She runs as ___ (fast) as her brother.","accepted_answers":["fast"]}', 'as + adj + as = so sánh bằng.', 1, '2026-04-22 03:56:53', '2026-04-22 03:56:53');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db355-e3b7-70be-8d50-afc92c9dd73f', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'mcq', '{"prompt":"___ the high cost, many people still buy electric cars.","options":["Although","Despite","However","Therefore"],"correct_index":1}', 'Despite + noun phrase.', 0, '2026-04-22 03:57:23', '2026-04-22 03:57:23');
INSERT INTO public.grammar_exercises (id, grammar_point_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db355-e3b9-73a2-9a99-210ec8faa19b', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'mcq', '{"prompt":"The company lost money. ___, it continued to expand.","options":["Therefore","Furthermore","Nevertheless","Although"],"correct_index":2}', 'Nevertheless = tuy nhiên, dùng đầu câu.', 1, '2026-04-22 03:57:23', '2026-04-22 03:57:23');
