INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019da080-5435-72de-ad04-178ff0f21e8d', '019da080-5431-70ff-879a-291264d520f9', 'S + have/has + V3/ed', 'Cấu trúc cơ bản.', 0);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db352-9df9-7388-98bd-0815cc175b9b', '019da080-5431-70ff-879a-291264d520f9', 'S + have/has + not + V3/ed', 'Phủ định', 1);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db352-e5f2-72dc-a868-f2e309b7fbba', '019db352-e5e8-71cb-b823-fb7267deae77', 'S + be + V3/ed (+ by + agent)', 'Bị động cơ bản', 0);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db352-e5f3-70ac-9ccb-2a8f915b4eb2', '019db352-e5e8-71cb-b823-fb7267deae77', 'S + have/has + been + V3/ed', 'Bị động thì hiện tại hoàn thành', 1);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db352-e5f4-7096-bb76-0aeca23df89d', '019db352-e5e8-71cb-b823-fb7267deae77', 'S + will + be + V3/ed', 'Bị động tương lai', 2);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db353-497a-71c9-854e-36e968b24e75', '019db353-4972-712f-a59a-65ee965fdbad', 'If + S + V(present), S + will + V', 'Type 1 — điều kiện có thể xảy ra', 0);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db353-497b-73ef-b834-7c961537691c', '019db353-4972-712f-a59a-65ee965fdbad', 'If + S + V(past), S + would + V', 'Type 2 — điều kiện giả định', 1);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db353-497b-73ef-b834-7c9615b1489a', '019db353-4972-712f-a59a-65ee965fdbad', 'If + S + had + V3, S + would have + V3', 'Type 3 — điều kiện không thể xảy ra', 2);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db353-950d-7096-82fa-6e61b31cf088', '019db353-9503-70c9-aa6b-e66b5d472234', 'N + who/that + V (người)', 'Chủ ngữ là người', 0);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db353-950e-70df-a876-1734bc05f64c', '019db353-9503-70c9-aa6b-e66b5d472234', 'N + which/that + V (vật)', 'Chủ ngữ là vật', 1);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db353-950f-7013-b2e1-1257e072f696', '019db353-9503-70c9-aa6b-e66b5d472234', 'N + whose + N (sở hữu)', 'Sở hữu', 2);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db353-dedb-70a3-b388-1bb5820bbe83', '019db353-ded2-7348-8607-6426d410f8c3', 'S + modal + V (bare infinitive)', 'Cấu trúc cơ bản', 0);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db353-dedb-70a3-b388-1bb582b8fd4a', '019db353-ded2-7348-8607-6426d410f8c3', 'S + modal + have + V3', 'Suy đoán về quá khứ', 1);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db354-6288-73f6-8a4b-962d73515e2b', '019db354-6281-712e-b01a-c37789241547', 'S + said (that) + S + V(past)', 'Tường thuật câu khẳng định', 0);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db354-6289-701d-8b05-75c5d34b6628', '019db354-6281-712e-b01a-c37789241547', 'S + asked + O + if/whether + S + V(past)', 'Tường thuật câu hỏi yes/no', 1);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db354-cb11-7201-a7e2-66e39637e47a', '019db354-cb0a-70e6-997d-3c9ee87bfcdd', 'a/an + singular countable noun (first mention)', 'Lần đầu nhắc đến', 0);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db354-cb12-71ca-baae-911270e41066', '019db354-cb0a-70e6-997d-3c9ee87bfcdd', 'the + noun (specific/unique)', 'Đã xác định hoặc duy nhất', 1);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db355-1c83-734c-b977-3fb3f2de36d1', '019db355-1c7b-70e1-b753-ec6176efcd01', 'enjoy/avoid/suggest/consider + V-ing', 'Động từ theo sau bởi gerund', 0);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db355-1c84-70c1-b86d-d46af72b90cd', '019db355-1c7b-70e1-b753-ec6176efcd01', 'want/hope/decide/plan + to + V', 'Động từ theo sau bởi infinitive', 1);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db355-1c84-70c1-b86d-d46af75608ff', '019db355-1c7b-70e1-b753-ec6176efcd01', 'remember/forget/stop + V-ing vs to V (nghĩa khác nhau)', 'Động từ dùng được cả hai', 2);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db355-6f63-7072-bd88-e26a62729b09', '019db355-6f5a-70d9-97e4-9862ed349b16', 'adj-er + than / more + adj + than', 'So sánh hơn', 0);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db355-6f64-7111-8503-aec5c308a1fd', '019db355-6f5a-70d9-97e4-9862ed349b16', 'the + adj-est / the most + adj', 'So sánh nhất', 1);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db355-6f65-7315-ac31-8d239a71dd30', '019db355-6f5a-70d9-97e4-9862ed349b16', 'as + adj + as', 'So sánh bằng', 2);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db355-e3ac-7250-ab97-8221e9f027e7', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'Addition: furthermore, moreover, in addition, besides', 'Thêm ý', 0);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db355-e3ac-7250-ab97-8221eabe3324', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'Contrast: however, nevertheless, on the other hand, although', 'Đối lập', 1);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db355-e3ad-7028-8ed1-f8bb4d84084b', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'Cause/Effect: therefore, consequently, as a result, thus', 'Nguyên nhân/kết quả', 2);
INSERT INTO public.grammar_structures (id, grammar_point_id, template, description, display_order) VALUES ('019db355-e3ae-71d7-9032-aadfeead9f73', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'Concession: although, even though, despite, in spite of', 'Nhượng bộ', 3);
INSERT INTO public.grammar_vstep_tips (id, grammar_point_id, task, tip, example, display_order) VALUES ('019da080-5439-724b-832f-6bc58d2cb0b5', '019da080-5431-70ff-879a-291264d520f9', 'WT2', 'Dùng present perfect để nêu kinh nghiệm trong essay.', 'Many students have experienced online learning.', 0);
INSERT INTO public.grammar_vstep_tips (id, grammar_point_id, task, tip, example, display_order) VALUES ('019db352-e5fa-717e-b6d7-46b256302473', '019db352-e5e8-71cb-b823-fb7267deae77', 'WT2', 'Dùng bị động để viết văn học thuật, tránh dùng I quá nhiều.', 'It has been argued that technology improves education.', 0);
INSERT INTO public.grammar_vstep_tips (id, grammar_point_id, task, tip, example, display_order) VALUES ('019db353-4982-70f7-bf95-2fb98e3073ab', '019db353-4972-712f-a59a-65ee965fdbad', 'WT2', 'Dùng type 2 để đề xuất giải pháp giả định trong essay.', 'If governments invested more in education, poverty rates would decrease significantly.', 0);
INSERT INTO public.grammar_vstep_tips (id, grammar_point_id, task, tip, example, display_order) VALUES ('019db353-9515-73f1-88c1-98190211fc4f', '019db353-9503-70c9-aa6b-e66b5d472234', 'WT2', 'Dùng relative clauses để viết câu phức tạp hơn, tránh lặp từ.', 'Technology, which has transformed education, offers new learning opportunities.', 0);
INSERT INTO public.grammar_vstep_tips (id, grammar_point_id, task, tip, example, display_order) VALUES ('019db353-dee3-7152-9630-17708e2223de', '019db353-ded2-7348-8607-6426d410f8c3', 'WT2', 'Dùng should/could/might để đề xuất giải pháp trong essay.', 'Governments should invest more in public transport to reduce congestion.', 0);
INSERT INTO public.grammar_vstep_tips (id, grammar_point_id, task, tip, example, display_order) VALUES ('019db354-628f-700a-bb18-9e21f2686bca', '019db354-6281-712e-b01a-c37789241547', 'WT1', 'Dùng reported speech khi viết thư tường thuật lại cuộc trò chuyện.', 'My friend told me that the event had been cancelled.', 0);
INSERT INTO public.grammar_vstep_tips (id, grammar_point_id, task, tip, example, display_order) VALUES ('019db354-cb19-7025-8e87-e8eb8e222f4c', '019db354-cb0a-70e6-997d-3c9ee87bfcdd', 'WT2', 'Dùng the khi nhắc lại khái niệm đã giới thiệu trong đoạn trước.', 'Technology has changed education. The impact of technology is undeniable.', 0);
INSERT INTO public.grammar_vstep_tips (id, grammar_point_id, task, tip, example, display_order) VALUES ('019db355-1c8c-700f-849f-f4acae139bc6', '019db355-1c7b-70e1-b753-ec6176efcd01', 'WT2', 'Dùng gerund sau preposition để viết câu đa dạng hơn.', 'By investing in education, governments can reduce poverty.', 0);
INSERT INTO public.grammar_vstep_tips (id, grammar_point_id, task, tip, example, display_order) VALUES ('019db355-6f6b-7119-b464-57f0694fdf32', '019db355-6f5a-70d9-97e4-9862ed349b16', 'WT2', 'Dùng comparative để so sánh hai quan điểm trong essay.', 'Online learning is more flexible than traditional classroom learning.', 0);
INSERT INTO public.grammar_vstep_tips (id, grammar_point_id, task, tip, example, display_order) VALUES ('019db355-e3b5-72fd-bf4f-f878006547a3', '019db355-e3a3-71d2-94a3-37f86d562d3c', 'WT2', 'Dùng đa dạng linking words để tăng điểm coherence trong essay.', 'Furthermore, governments should invest in renewable energy. Nevertheless, this requires significant funding.', 0);
INSERT INTO public.vocab_topics (id, slug, name, description, level, icon_key, display_order, is_published, created_at, updated_at) VALUES ('019da080-5429-7083-9f58-928b980c3575', 'family-life', 'Gia đình & Cuộc sống', 'Từ vựng về gia đình, mối quan hệ, cuộc sống hằng ngày.', 'B1', 'family', 1, true, '2026-04-18 12:10:57', '2026-04-18 12:10:57');
INSERT INTO public.vocab_topics (id, slug, name, description, level, icon_key, display_order, is_published, created_at, updated_at) VALUES ('019db158-edfe-7125-99d8-44a30e29b83b', 'ipsam-numquam-aQjt', 'Ipsam numquam', 'Quia nihil quibusdam veritatis iste error consequatur et qui.', 'C1', 'heart', 0, true, '2026-04-21 18:41:28', '2026-04-21 18:41:28');
