INSERT INTO public.vocab_topics (id, slug, name, description, level, icon_key, display_order, is_published, created_at, updated_at) VALUES ('019db350-bfd0-7174-b28a-9ff63d10f513', 'work-career', 'Work & Career', 'Từ vựng về công việc, nghề nghiệp.', 'B1', 'work', 5, true, '2026-04-22 03:51:46', '2026-04-22 03:51:46');
INSERT INTO public.vocab_topics (id, slug, name, description, level, icon_key, display_order, is_published, created_at, updated_at) VALUES ('019db351-2083-71dd-ae84-09fa3916e4cb', 'society-community', 'Society & Community', 'Từ vựng về xã hội, cộng đồng.', 'B2', 'society', 6, true, '2026-04-22 03:52:11', '2026-04-22 03:52:11');
INSERT INTO public.vocab_topics (id, slug, name, description, level, icon_key, display_order, is_published, created_at, updated_at) VALUES ('019db351-6e23-726c-8870-d8e910642d4e', 'travel-tourism', 'Travel & Tourism', 'Từ vựng về du lịch, đi lại.', 'B1', 'travel', 7, true, '2026-04-22 03:52:31', '2026-04-22 03:52:31');
