INSERT INTO public.vocab_topics (id, slug, name, description, level, icon_key, display_order, is_published, created_at, updated_at) VALUES ('019db352-0181-7199-9b4a-df655a6db623', 'culture-arts', 'Culture & Arts', 'Từ vựng về văn hóa, nghệ thuật.', 'B1', 'culture', 9, true, '2026-04-22 03:53:09', '2026-04-22 03:53:09');
INSERT INTO public.vocab_topics (id, slug, name, description, level, icon_key, display_order, is_published, created_at, updated_at) VALUES ('019db352-52cf-7063-b2ad-697f2231d0df', 'urban-rural-life', 'Urban & Rural Life', 'Từ vựng về cuộc sống đô thị và nông thôn.', 'B1', 'city', 10, true, '2026-04-22 03:53:30', '2026-04-22 03:53:30');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019da080-5430-72ea-b114-14268cd09880', '019da080-5429-7083-9f58-928b980c3575', 'mcq', '{"prompt":"A brother or sister is called a ___","options":["relative","sibling","cousin","partner"],"correct_index":1}', 'Sibling = anh chị em ruột.', 0, '2026-04-18 12:10:57', '2026-04-18 12:10:57');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019da080-5430-72ea-b114-14268d5f2d02', '019da080-5429-7083-9f58-928b980c3575', 'fill_blank', '{"sentence":"Parents ___ their children with love.","accepted_answers":["nurture"]}', 'Nurture = nuôi dưỡng.', 1, '2026-04-18 12:10:57', '2026-04-18 12:10:57');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db34f-7bb5-7114-afde-f0727a8335cf', '019db34f-7b9c-7346-a081-e041855828cf', 'mcq', '{"prompt":"The set of subjects taught at a school is called the ___.","options":["schedule","curriculum","timetable","syllabus"],"correct_index":1}', 'Curriculum = chương trình học tổng thể.', 0, '2026-04-22 03:50:23', '2026-04-22 03:50:23');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db34f-7bbd-72f4-86da-56dffc10aab5', '019db34f-7b9c-7346-a081-e041855828cf', 'fill_blank', '{"sentence":"Attendance at school is ___ for children aged 6-15.","accepted_answers":["compulsory","mandatory"]}', 'Compulsory = bắt buộc theo luật.', 1, '2026-04-22 03:50:23', '2026-04-22 03:50:23');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db34f-d3b4-709a-b044-78d883492bb8', '019db34f-d3a2-72d3-a223-143ad5b7fb4a', 'mcq', '{"prompt":"The cutting down of large areas of forest is called ___.","options":["erosion","deforestation","contamination","drought"],"correct_index":1}', 'Deforestation = phá rừng quy mô lớn.', 0, '2026-04-22 03:50:46', '2026-04-22 03:50:46');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db34f-d3b5-72e9-8b47-65f566cde25c', '019db34f-d3a2-72d3-a223-143ad5b7fb4a', 'fill_blank', '{"sentence":"Solar and wind power are examples of ___ energy.","accepted_answers":["renewable","sustainable"]}', 'Renewable energy = năng lượng tái tạo.', 1, '2026-04-22 03:50:46', '2026-04-22 03:50:46');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db350-1e83-736b-90d7-e6d735950a6f', '019db350-1e6f-726e-821a-45c3610c3955', 'mcq', '{"prompt":"A ___ is a sign that shows you may have an illness.","options":["cure","symptom","surgery","prescription"],"correct_index":1}', 'Symptom = triệu chứng bệnh.', 0, '2026-04-22 03:51:05', '2026-04-22 03:51:05');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db350-1e84-738d-9beb-6d9aea8ba028', '019db350-1e6f-726e-821a-45c3610c3955', 'fill_blank', '{"sentence":"Vaccines help build ___ against diseases.","accepted_answers":["immunity","resistance"]}', 'Immunity = khả năng miễn dịch.', 1, '2026-04-22 03:51:05', '2026-04-22 03:51:05');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db350-6b25-72f4-a79d-e9294bc2c775', '019db350-6b16-7346-bc99-52c6854a3028', 'mcq', '{"prompt":"The use of machines to do work automatically is called ___.","options":["innovation","algorithm","automation","disruption"],"correct_index":2}', 'Automation = tự động hóa bằng máy móc.', 0, '2026-04-22 03:51:25', '2026-04-22 03:51:25');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db350-6b26-705d-8613-0076fcdfb35c', '019db350-6b16-7346-bc99-52c6854a3028', 'fill_blank', '{"sentence":"The company developed a ___ before launching the final product.","accepted_answers":["prototype","model"]}', 'Prototype = nguyên mẫu thử nghiệm.', 1, '2026-04-22 03:51:25', '2026-04-22 03:51:25');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db350-bfdf-7093-bbfc-f9ac79d3fae4', '019db350-bfd0-7174-b28a-9ff63d10f513', 'mcq', '{"prompt":"A person who starts their own business is called an ___.","options":["employee","entrepreneur","intern","colleague"],"correct_index":1}', 'Entrepreneur = người khởi nghiệp.', 0, '2026-04-22 03:51:46', '2026-04-22 03:51:46');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db350-bfe0-71d9-be83-6cf8173d1055', '019db350-bfd0-7174-b28a-9ff63d10f513', 'fill_blank', '{"sentence":"She ___ a better salary before accepting the job offer.","accepted_answers":["negotiated","discussed"]}', 'Negotiate = đàm phán điều kiện.', 1, '2026-04-22 03:51:46', '2026-04-22 03:51:46');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db351-2093-720f-8fcd-2d96d9d29197', '019db351-2083-71dd-ae84-09fa3916e4cb', 'mcq', '{"prompt":"Treating people unfairly because of their race is called ___.","options":["integration","tolerance","discrimination","welfare"],"correct_index":2}', 'Discrimination = phân biệt đối xử.', 0, '2026-04-22 03:52:11', '2026-04-22 03:52:11');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db351-2094-7264-bef7-6bf7cf49b536', '019db351-2083-71dd-ae84-09fa3916e4cb', 'fill_blank', '{"sentence":"The government introduced programs to reduce ___ among low-income families.","accepted_answers":["poverty","inequality"]}', 'Poverty = tình trạng nghèo đói.', 1, '2026-04-22 03:52:11', '2026-04-22 03:52:11');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db351-6e34-72ca-b1c8-1e3a38beb641', '019db351-6e23-726c-8870-d8e910642d4e', 'mcq', '{"prompt":"A plan showing the places you will visit on a trip is called an ___.","options":["accommodation","itinerary","reservation","excursion"],"correct_index":1}', 'Itinerary = lịch trình chi tiết chuyến đi.', 0, '2026-04-22 03:52:31', '2026-04-22 03:52:31');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db351-6e35-7312-9312-01fa5ba3734d', '019db351-6e23-726c-8870-d8e910642d4e', 'fill_blank', '{"sentence":"All passengers must go through ___ before collecting their luggage.","accepted_answers":["customs","immigration"]}', 'Customs = hải quan kiểm tra hàng hóa.', 1, '2026-04-22 03:52:31', '2026-04-22 03:52:31');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db351-b848-72db-9408-7629b67829f5', '019db351-b839-72ed-8996-23109dcf7e4f', 'mcq', '{"prompt":"A general rise in prices over time is called ___.","options":["recession","deficit","inflation","subsidy"],"correct_index":2}', 'Inflation = lạm phát.', 0, '2026-04-22 03:52:50', '2026-04-22 03:52:50');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db351-b849-7083-b1f0-9039c0089140', '019db351-b839-72ed-8996-23109dcf7e4f', 'fill_blank', '{"sentence":"The government provides ___ to help farmers cover their costs.","accepted_answers":["subsidies","grants","support"]}', 'Subsidy = trợ cấp tài chính từ nhà nước.', 1, '2026-04-22 03:52:50', '2026-04-22 03:52:50');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db352-0195-7032-a388-d62f8325e7ad', '019db352-0181-7199-9b4a-df655a6db623', 'mcq', '{"prompt":"Things passed down from previous generations are called ___.","options":["folklore","heritage","sculpture","manuscript"],"correct_index":1}', 'Heritage = di sản văn hóa từ thế hệ trước.', 0, '2026-04-22 03:53:09', '2026-04-22 03:53:09');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db352-0196-73f0-8556-747407b32d95', '019db352-0181-7199-9b4a-df655a6db623', 'fill_blank', '{"sentence":"The museum held an ___ of modern Vietnamese paintings.","accepted_answers":["exhibition","exhibit","show"]}', 'Exhibition = triển lãm nghệ thuật.', 1, '2026-04-22 03:53:09', '2026-04-22 03:53:09');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db352-52e3-71f2-af26-0b715028db88', '019db352-52cf-7063-b2ad-697f2231d0df', 'mcq', '{"prompt":"The process of more people moving to cities is called ___.","options":["gentrification","commute","urbanization","migration"],"correct_index":2}', 'Urbanization = quá trình đô thị hóa.', 0, '2026-04-22 03:53:30', '2026-04-22 03:53:30');
INSERT INTO public.vocab_exercises (id, topic_id, kind, payload, explanation, display_order, created_at, updated_at) VALUES ('019db352-52e4-7036-9174-542eaec55a2e', '019db352-52cf-7063-b2ad-697f2231d0df', 'fill_blank', '{"sentence":"Heavy traffic ___ makes it difficult to drive in the city center.","accepted_answers":["congestion","traffic"]}', 'Congestion = tắc nghẽn giao thông.', 1, '2026-04-22 03:53:30', '2026-04-22 03:53:30');
